12	};
13	
14	export function ClarificationPanel({
15	  questions,
16	  answerDrafts,
17	  submittingId,
18	  onDraftChange,
19	  onSubmit
20	}: ClarificationPanelProps): ReactElement | null {
21	  if (questions.length === 0) return null;
22	
23	  return (
24	    <section className="clarification-panel">
25	      <header>
