32	        {questions.map((question) => {
33	          const answered = Boolean(question.answer);
34	          return (
35	            <article
36	              className={`clarification-card ${answered ? "answered" : "pending"}`}
37	              data-status={answered ? "answered" : "unanswered"}
38	              key={question.id}
39	            >
40	              <div className="clarification-question">
41	                {answered ? <Check size={16} /> : <CircleDashed size={16} />}
42	                <MarkdownBlock source={question.question} compact />
43	              </div>
44	              {answered ? (
45	                <div className="clarification-answer">
46	                  <span>Answer</span>
47	                  <MarkdownBlock source={question.answer ?? ""} compact />
48	                </div>
49	              ) : (
50	                <div className="clarification-form">
51	                  <textarea
52	                    value={answerDrafts[question.id] ?? ""}
53	                    onChange={(event) => onDraftChange(question.id, event.target.value)}
54	                    placeholder="Answer"
55	                  />
56	                  <button
57	                    className="primary-button"
58	                    onClick={() => onSubmit(question.id)}
59	                    disabled={submittingId === question.id || !(answerDrafts[question.id] ?? "").trim()}
60	                  >
61	                    <Send size={15} />
62	                    Submit Answer
63	                  </button>
64	                </div>
65	              )}
66	            </article>
67	          );
68	        })}
69	      </div>
70	    </section>
71	  );
72	}

